/**
 * Organization Module Service Tests
 *
 * Unit tests for OrganizationService covering:
 * - Organization CRUD operations
 * - Settings management
 * - Status changes
 * - Slug and email validation
 * - Soft delete and restore
 *
 * @module modules/_core/organization/__tests__/organization.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';
import { OrganizationStatus } from '@prisma/client';

import { OrganizationService } from '@/modules/_core/organization/organization.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { EventService } from '@/core/services/event.service';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock OrganizationRepository
 */
function createMockRepository() {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findBySlugOrThrow: vi.fn(),
    slugExists: vi.fn(),
    emailExists: vi.fn(),
    count: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateSettings: vi.fn(),
    updateStatus: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): { emitCustom: Mock } {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock organization for testing
 */
function createMockOrganization(overrides: Partial<{
  id: string;
  name: string;
  slug: string;
  email: string;
  phone: string | null;
  logo: string | null;
  settings: Record<string, unknown>;
  status: OrganizationStatus;
  planId: string | null;
  trialEndsAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}> = {}) {
  return {
    id: 'org_123',
    name: 'Test Organization',
    slug: 'test-organization',
    email: 'test@organization.com',
    phone: '+905551234567',
    logo: null,
    settings: { currency: 'TRY', language: 'tr' },
    status: OrganizationStatus.ACTIVE,
    planId: null,
    trialEndsAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('OrganizationService', () => {
  let service: OrganizationService;
  let mockRepository: ReturnType<typeof createMockRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  beforeEach(() => {
    mockRepository = createMockRepository();
    mockEventService = createMockEventService();

    service = new OrganizationService(
      mockRepository as unknown as Parameters<typeof OrganizationService['prototype']['constructor']>[0],
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // List Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated organizations', async () => {
      // Arrange
      const mockOrgs = [createMockOrganization(), createMockOrganization({ id: 'org_456' })];
      mockRepository.findAll.mockResolvedValue({
        data: mockOrgs,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      });

      // Act
      const result = await service.list({ page: 1, perPage: 20 });

      // Assert
      expect(result.data).toHaveLength(2);
      expect(result.meta.total).toBe(2);
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        expect.objectContaining({ page: 1, perPage: 20 })
      );
    });

    it('should apply status filter', async () => {
      // Arrange
      mockRepository.findAll.mockResolvedValue({
        data: [],
        meta: { page: 1, perPage: 20, total: 0, totalPages: 0 },
      });

      // Act
      await service.list({ status: OrganizationStatus.ACTIVE });

      // Assert
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        expect.objectContaining({ status: OrganizationStatus.ACTIVE })
      );
    });
  });

  describe('listSummaries', () => {
    it('should return organization summaries', async () => {
      // Arrange
      const mockSummaries = [
        { id: 'org_1', name: 'Org 1', slug: 'org-1' },
        { id: 'org_2', name: 'Org 2', slug: 'org-2' },
      ];
      mockRepository.findAllSummaries.mockResolvedValue(mockSummaries);

      // Act
      const result = await service.listSummaries();

      // Assert
      expect(result).toHaveLength(2);
      expect(mockRepository.findAllSummaries).toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('getById', () => {
    it('should return organization by ID', async () => {
      // Arrange
      const mockOrg = createMockOrganization();
      mockRepository.findById.mockResolvedValue(mockOrg);

      // Act
      const result = await service.getById('org_123');

      // Assert
      expect(result).toEqual(mockOrg);
      expect(mockRepository.findById).toHaveBeenCalledWith('org_123');
    });

    it('should return null when organization not found', async () => {
      // Arrange
      mockRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById('nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return organization with relations', async () => {
      // Arrange
      const mockOrg = createMockOrganization();
      mockRepository.findByIdWithRelations.mockResolvedValue(mockOrg);

      // Act
      const result = await service.getByIdWithRelations('org_123');

      // Assert
      expect(result).toEqual(mockOrg);
    });

    it('should throw error when organization not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(service.getByIdWithRelations('nonexistent')).rejects.toThrow(AppException);
    });
  });

  describe('getBySlug', () => {
    it('should return organization by slug', async () => {
      // Arrange
      const mockOrg = createMockOrganization();
      mockRepository.findBySlug.mockResolvedValue(mockOrg);

      // Act
      const result = await service.getBySlug('test-organization');

      // Assert
      expect(result).toEqual(mockOrg);
      expect(mockRepository.findBySlug).toHaveBeenCalledWith('test-organization');
    });
  });

  describe('getSettings', () => {
    it('should return organization settings', async () => {
      // Arrange
      const mockOrg = createMockOrganization({
        settings: { currency: 'TRY', timezone: 'Europe/Istanbul' },
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(mockOrg);

      // Act
      const result = await service.getSettings('org_123');

      // Assert
      expect(result).toEqual({ currency: 'TRY', timezone: 'Europe/Istanbul' });
    });
  });

  describe('count', () => {
    it('should return organization count', async () => {
      // Arrange
      mockRepository.count.mockResolvedValue(10);

      // Act
      const result = await service.count();

      // Assert
      expect(result).toBe(10);
    });

    it('should filter by status', async () => {
      // Arrange
      mockRepository.count.mockResolvedValue(5);

      // Act
      await service.count(OrganizationStatus.ACTIVE);

      // Assert
      expect(mockRepository.count).toHaveBeenCalledWith(OrganizationStatus.ACTIVE);
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      name: 'New Restaurant',
      email: 'contact@newrestaurant.com',
      phone: '+905551234567',
    };

    it('should create organization successfully', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(false);
      mockRepository.emailExists.mockResolvedValue(false);
      const createdOrg = createMockOrganization({
        id: 'org_new',
        name: validCreateData.name,
        email: validCreateData.email,
      });
      mockRepository.create.mockResolvedValue(createdOrg);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(validCreateData);

      // Assert
      expect(result.organization).toEqual(createdOrg);
      expect(result.message).toContain('successfully');
      expect(mockRepository.create).toHaveBeenCalledWith(
        expect.objectContaining({
          name: validCreateData.name,
          email: validCreateData.email,
        })
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.created',
        expect.objectContaining({
          organizationId: createdOrg.id,
          name: createdOrg.name,
        })
      );
    });

    it('should auto-generate unique slug', async () => {
      // Arrange
      mockRepository.slugExists
        .mockResolvedValueOnce(true)  // First slug exists
        .mockResolvedValueOnce(false); // Second slug available
      mockRepository.emailExists.mockResolvedValue(false);
      mockRepository.create.mockResolvedValue(createMockOrganization({ slug: 'new-restaurant-1' }));
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(validCreateData);

      // Assert
      expect(mockRepository.slugExists).toHaveBeenCalledTimes(2);
    });

    it('should throw error when slug already exists (custom slug)', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.create({ ...validCreateData, slug: 'existing-slug' })
      ).rejects.toThrow(AppException);

      expect(mockRepository.create).not.toHaveBeenCalled();
    });

    it('should throw error when email already exists', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(false);
      mockRepository.emailExists.mockResolvedValue(true);

      // Act & Assert
      await expect(service.create(validCreateData)).rejects.toThrow(AppException);

      expect(mockRepository.create).not.toHaveBeenCalled();
    });

    it('should throw validation error for invalid email', async () => {
      // Arrange
      const invalidData = { ...validCreateData, email: 'invalid-email' };

      // Act & Assert
      await expect(service.create(invalidData)).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      name: 'Updated Restaurant',
    };

    it('should update organization successfully', async () => {
      // Arrange
      const currentOrg = createMockOrganization();
      const updatedOrg = createMockOrganization({ name: validUpdateData.name });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);
      mockRepository.update.mockResolvedValue(updatedOrg);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update('org_123', validUpdateData);

      // Assert
      expect(result.organization.name).toBe(validUpdateData.name);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.updated',
        expect.objectContaining({
          organizationId: 'org_123',
        })
      );
    });

    it('should check slug uniqueness when updating slug', async () => {
      // Arrange
      const currentOrg = createMockOrganization({ slug: 'old-slug' });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);
      mockRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update('org_123', { slug: 'existing-slug' })
      ).rejects.toThrow(AppException);
    });

    it('should check email uniqueness when updating email', async () => {
      // Arrange
      const currentOrg = createMockOrganization({ email: 'old@email.com' });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);
      mockRepository.emailExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update('org_123', { email: 'existing@email.com' })
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateSettings', () => {
    it('should update settings successfully', async () => {
      // Arrange
      const currentOrg = createMockOrganization({ settings: { currency: 'TRY' } });
      const updatedOrg = createMockOrganization({
        settings: { currency: 'TRY', timezone: 'Europe/Istanbul' },
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);
      mockRepository.updateSettings.mockResolvedValue(updatedOrg);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateSettings('org_123', {
        settings: { timezone: 'Europe/Istanbul' },
      });

      // Assert
      expect(result.settings).toEqual({ currency: 'TRY', timezone: 'Europe/Istanbul' });
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.settings.updated',
        expect.any(Object)
      );
    });
  });

  describe('changeStatus', () => {
    it('should change status successfully', async () => {
      // Arrange
      const currentOrg = createMockOrganization({ status: OrganizationStatus.ACTIVE });
      const updatedOrg = createMockOrganization({ status: OrganizationStatus.SUSPENDED });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);
      mockRepository.updateStatus.mockResolvedValue(updatedOrg);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changeStatus('org_123', {
        status: OrganizationStatus.SUSPENDED,
        reason: 'Non-payment',
      });

      // Assert
      expect(result.organization.status).toBe(OrganizationStatus.SUSPENDED);
      expect(result.previousStatus).toBe(OrganizationStatus.ACTIVE);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.status.changed',
        expect.objectContaining({
          previousStatus: OrganizationStatus.ACTIVE,
          newStatus: OrganizationStatus.SUSPENDED,
        })
      );
    });

    it('should return unchanged message when status is same', async () => {
      // Arrange
      const currentOrg = createMockOrganization({ status: OrganizationStatus.ACTIVE });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentOrg);

      // Act
      const result = await service.changeStatus('org_123', {
        status: OrganizationStatus.ACTIVE,
      });

      // Assert
      expect(result.message).toContain('unchanged');
      expect(mockRepository.updateStatus).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete organization successfully', async () => {
      // Arrange
      const mockOrg = createMockOrganization();
      mockRepository.findByIdOrThrow.mockResolvedValue(mockOrg);
      mockRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete('org_123');

      // Assert
      expect(mockRepository.softDelete).toHaveBeenCalledWith('org_123');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.deleted',
        expect.objectContaining({
          organizationId: 'org_123',
        })
      );
    });
  });

  describe('restore', () => {
    it('should restore organization successfully', async () => {
      // Arrange
      const restoredOrg = createMockOrganization();
      mockRepository.restore.mockResolvedValue(restoredOrg);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore('org_123');

      // Assert
      expect(result).toEqual(restoredOrg);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'organization.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Validation Operations Tests
  // ---------------------------------------------------------------------------

  describe('isSlugAvailable', () => {
    it('should return true when slug is available', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(false);

      // Act
      const result = await service.isSlugAvailable('new-slug');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when slug exists', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(true);

      // Act
      const result = await service.isSlugAvailable('existing-slug');

      // Assert
      expect(result).toBe(false);
    });
  });

  describe('isEmailAvailable', () => {
    it('should return true when email is available', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);

      // Act
      const result = await service.isEmailAvailable('new@email.com');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when email exists', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(true);

      // Act
      const result = await service.isEmailAvailable('existing@email.com');

      // Assert
      expect(result).toBe(false);
    });
  });
});
